INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05750', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據領導的互動模型（interactional model），領導是團體發展時，許多互動因素產生的結果，這些因素包', '["團體目的", "問題類型", "團體領導者", "團體成員  ⑤團體成員家人  ⑥整個團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05751', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「將團體視為一個完整型態（gestalt），亦即每一個團體都有一個生命空間，它占有一個位置，團體成員 在團體中可以相互支撐，並朝向達致團體目標的方向前進。所有個別團體成員和團體本身的行為，均應 被視為團體所有情境功能的表現」這是那一個團體工作理論的基本概念？', '["敘事與結構理論（narrative and constructivist theories）", "場域理論（field theory）", "心理動力理論（psychodynamic theory）", "系統理論（system theory）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05752', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「多元文化團體工作」的論述，下列何者錯誤？', '["團體工作者應該將「社會正義」（social justice）的觀點運用在團體工作實務中", "幫助成員確認及建立自己的優勢，並發展自我倡導的技巧，是多元文化團體工作重要的運作策略之一", "團體成員所面臨的問題，通常與社會文化脈絡沒有直接相關", "團體工作者應鼓勵成員思考並了解彼此的文化背景與世界觀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05753', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「團體思考」（group thinking）的敘述，下列何者錯誤？', '["當團體凝聚力愈強時，成員不願出現與其他成員不一致的態度或想法，則容易形成團體思考", "任務性團體中，出現一致性的團體思考，對於團體做出具有共識性的最佳決策是有益的", "工作者應該帶領成員挑戰團體決策，以降低團體思考的發展與壓抑團體決策創新思維的展現", "成員較有意願支持與自身價值偏好相近的意見，易於忽略他們不喜歡的意見，這是形成團體思考的原 因之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05754', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某個理論提醒社區工作者在面對複雜與多變的社區環境時，必須思考其因果關係，無論是消極面或積極 面，都應該儘量避免倉促決定其中的一個層面，而將另一個層面的因素排除在外。這個社區工作理論是：', '["社會交換理論（Social Exchange Theory）", "社會學習理論（Social Learning Theory）", "系統理論（System Theory）", "混沌理論（Chaos Theory）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05755', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區需求評估（community needs assessment）是社區工作的重要項目之一。評估社區需求，則有多元的方 法。「從社區工作者本身的機構或其他組織進行書面資料的蒐集，如機構紀錄、服務案例、相關的研究 報告與文獻、官方資料等，來評估社區需求」，上述這種社區需求評估方法是：', '["由軟體資訊進行社區需求評估", "由硬體資訊進行社區需求評估", "透過重要人士訪談進行社區需求評估", "透過社區會議進行社區需求評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05756', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「某社區中心確認某弱勢居民有居家環境清理的需求，但該中心卻無力單獨完成環境清理工作，就提出 弱勢居民環境清理方案，公開徵求服務資源，包括：贊助資金、連結清潔人員、提供清潔用品與環境清 理技術等，形成一個環境清理的基本組織或團體」。若依Netting等人（2008）的界定，此社區組織與其 他單位之間互動的層次為：', '["溝通（communication）", "合作（cooperation）", "夥伴（collaboration）", "聯盟（confederation）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05757', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「社會住宅」（social housing）的敘述，下列何者錯誤？', '["任何人都不得對於社會住宅的承租戶、承買戶或借款人有不合理之歧視待遇", "政府對於因重大災難造成之房屋損害，應有妥善之社區與住宅重建計畫，興建社會住宅便是其中一種策略", "依據民國 100 年行政院提出的「社會住宅實施方案」，社會住宅只提供給獨居老人、身心障礙者等弱 勢族群", "社會住宅若能採取與一般住宅混合興建，將能降低社會住宅被標籤為「貧民窟」的可能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05758', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '災後社區重建是臺灣目前社區工作重要且新興發展的工作領域之一，對於災後社區重建的敘述，下列何 者錯誤？', '["在災後社區重建過程，住宅或家屋的興建，經費與安全性是最重要的考量原則，至於住宅與家屋的外 觀是否為社區居民認同，則應列為次要考量的原則", "在災後社區重建階段，社區工作者主要的任務，是協助社區組織或社區團體發揮重建的功能，致力於 社區復原或重建的工作", "災後社區重建過程大致符合社區工作的實施程序，依循著社區需求評估、動員社區組織、規劃執行及 評估社區方案等過程", "災後社區重建工作應以社區需求為基礎，並鼓勵社區居民參與規劃與執行的過程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05759', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '和社區資源維繫良好關係，是社區工作者重要的工作任務之一。關於社區資源維繫的敘述，下列何者錯誤？', '["不管是社區內部或外部資源，對於資源的使用過程，應該儘量透明化，以符合責信原則", "社區資源的運用是為了協助社區解決問題或提供服務，因而必須以社區居民的實際需求為前提", "為了增加與某些社區資源更密切的互動機會，在社區資源的使用上，儘量集中在某些提供資源的個人 與團體", "為因應社區居民多元且複雜的需求，並減少社區資源使用的重複與浪費，社區工作者應進行資源的統 整與協調"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
